import{_ as a,c as i,o as e,aN as n}from"./chunks/framework.CMIDsdwV.js";const k=JSON.parse('{"title":"OpenClaw 安装【Mac版】","description":"","frontmatter":{"title":"OpenClaw 安装【Mac版】","date":"2026-03-08","permalink":"/aigc/development/open-claw/install-mac","tags":["AI应用开发","OpenClaw"],"categories":["AI应用开发","OpenClaw"]},"headers":[],"relativePath":"AIGC/AI应用开发/03.OpenClaw/2_OpenClaw安装【Mac版】.md","filePath":"AIGC/AI应用开发/03.OpenClaw/2_OpenClaw安装【Mac版】.md","lastUpdated":1773075361000}'),p={name:"AIGC/AI应用开发/03.OpenClaw/2_OpenClaw安装【Mac版】.md"};function l(t,s,h,r,d,o){return e(),i("div",null,[...s[0]||(s[0]=[n('<div style="display:none;" hidden="true" aria-hidden="true">Are you an LLM? You can read better optimized documentation at /AIGC\\AI应用开发\\03.OpenClaw\\2_OpenClaw安装【Mac版】.md for this page in Markdown format</div><h1 id="openclaw-安装教程【mac版】" tabindex="-1">OpenClaw 安装教程【Mac版】 <a class="header-anchor" href="#openclaw-安装教程【mac版】" aria-label="Permalink to &quot;OpenClaw 安装教程【Mac版】&quot;">​</a></h1><h2 id="一、安装-homebrew" tabindex="-1">一、安装 Homebrew <a class="header-anchor" href="#一、安装-homebrew" aria-label="Permalink to &quot;一、安装 Homebrew&quot;">​</a></h2><blockquote><p><strong>Homebrew</strong> 是 macOS 和 Linux 上的一个包管理器，类似于 Windows 的 <strong>choco</strong> 或 <strong>scoop</strong>。可以帮助用户轻松安装、更新、卸载和管理各种软件包，包括命令行工具、GUI 应用和系统服务。</p><p>官网地址：<a href="https://brew.sh/zh-cn/" target="_blank" rel="noreferrer">https://brew.sh/zh-cn/</a></p></blockquote><p>应用程序APP中搜索终端（Terminal）并打开。</p><p>在终端输入安装命令：</p><div class="language-sh vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">/bin/zsh</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -c</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;$(</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -fsSL</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://gitee.com/cunkai/HomebrewCN/raw/master/Homebrew.sh)&quot;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>执行后按提示操作：</p><ol><li>选择下载源，输入 1（清华大学镜像）</li><li>输入电脑开机密码</li><li>如果询问是否删除旧版本 Homebrew，输入 Y</li><li>按回车开始安装</li><li>选择镜像源时输入 5（阿里镜像）</li></ol><p>安装完成后，关闭终端，再重新打开终端，查看 Brew 的版本信息：</p><div class="language-sh vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">brew</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --version</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>Homebrew 安装完成。</p><h2 id="二、安装-git" tabindex="-1">二、安装 Git <a class="header-anchor" href="#二、安装-git" aria-label="Permalink to &quot;二、安装 Git&quot;">​</a></h2><blockquote><p>Git 是一种<strong>分布式版本控制系统</strong>，核心作用是帮助个人或团队高效管理文件版本、协作开发，并保障代码安全。</p></blockquote><p>在终端输入命令：</p><div class="language-sh vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">brew</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> git</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>回车执行，等待安装完成，查看版本：</p><div class="language-sh vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -v</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>Git 安装完成。</p><h2 id="三、安装-node-js" tabindex="-1">三、安装 Node.js <a class="header-anchor" href="#三、安装-node-js" aria-label="Permalink to &quot;三、安装 Node.js&quot;">​</a></h2><blockquote><p>Node.js是一个开源的、跨平台的JavaScript运行环境，它允许开发者使用JavaScript来编写服务器端的代码。</p></blockquote><p>进入官网：</p><p><a href="https://nodejs.org/zh-cn/download" target="_blank" rel="noreferrer">https://nodejs.org/zh-cn/download</a></p><p>下载 macOS 版安装程序。</p><p>安装步骤：</p><ol><li>打开下载好的安装包</li><li>点击继续</li><li>同意用户协议</li><li>点击安装</li><li>输入电脑密码</li><li>点击安装软件</li></ol><p>安装完成后，查看安装的版本：</p><div class="language-sh vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">node</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -v</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>Node.js 安装完成。</p><h2 id="四、安装-openclaw" tabindex="-1">四、安装 OpenClaw <a class="header-anchor" href="#四、安装-openclaw" aria-label="Permalink to &quot;四、安装 OpenClaw&quot;">​</a></h2><p>打开终端。</p><p>首先输入下方命令，将 npm 下载源切换为国内镜像，提高下载速度：</p><div class="language-sh vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> config</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> set</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> registry</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://registry.npmmirror.com</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>然后输入下方命令，避免 GitHub 的 SSH 配置问题：</p><div class="language-sh vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> config</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --global</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> url.&quot;https://github.com/&quot;.insteadOf</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ssh://git@github.com/</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>最后执行安装命令：</p><div class="language-sh vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -g</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> openclaw@latest</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>输入电脑密码并回车，等待安装完成。</p><p>如果终端出现类似 <code>added xxx packages</code> 的提示，说明安装成功。</p><p>OpenClaw 安装完成。</p><p>通过下面的命令，可以查看安装的版本：</p><div class="language-sh vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openclaw</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -v</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h2 id="五、初始化配置-openclaw" tabindex="-1">五、初始化配置 OpenClaw <a class="header-anchor" href="#五、初始化配置-openclaw" aria-label="Permalink to &quot;五、初始化配置 OpenClaw&quot;">​</a></h2><p>在终端输入：</p><div class="language-sh vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> rm</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -rf</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/.openclaw/extensions/feishu</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>作用：删除旧的飞书插件目录，避免插件冲突。</p><p>然后启动初始化配置向导：</p><div class="language-sh vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openclaw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> onboard</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>Openclaw 会提示风险 <code>I understand this is personal-by-default and shared/multi-user use requires lock-down. Continue?</code></p><ul><li><p>风险提示：按键盘上的左右方向键选择，Yes</p></li><li><p>Onboarding mode（模式）：QuickStart</p></li><li><p>Model/auth provider（模型服务商）：任选（如 OpenAI / Anthropic / Moonshot AI (Kimi K2.5)）</p></li><li><p>Select channel（通讯渠道）：Skip for now</p></li><li><p>Configure skills now（技能）：按空格选择 Skip for now</p></li><li><p>API Key（密钥）：没有可以先选 No</p></li><li><p>Enable hooks（自动执行）：Skip for now</p></li><li><p>How do you want to hatch your bot（以什么方式启动🦞）：选择 Open the Web UI 启动</p></li></ul><p>会自动在浏览器打开 <a href="http://127.0.0.1:18789/chat?session=main" target="_blank" rel="noreferrer">http://127.0.0.1:18789/chat?session=main</a></p><p>如果出现聊天界面，说明配置成功。</p>',52)])])}const u=a(p,[["render",l]]);export{k as __pageData,u as default};
